INSERT INTO `categories` VALUES (1,NULL,'Fashion','fashion','Celebrate Indonesia\'s style heritage, from timeless batik to contemporary designs. Discover fashion that connects tradition with today\'s lifestyle.',1,1,0,'category/ZgA3UjIrmti9EhoE9BF3ggQvUCc3z1t5DDtuI7Gv.png','Fashion Indonesia: Batik & Modern Style | Sarinah ECommerce 2025','Celebrate Indonesia\'s fashion heritage with Sarinah. Discover timeless batik and contemporary designs that connect tradition with today’s lifestyle.','fashion, Indonesia, batik, contemporary style, Sarinah, heritage, modern lifestyle, ecommerce, clothing, design','2025-11-21 08:26:23','2025-12-02 03:02:32'),(2,NULL,'Food','food','Discover delicious food selections at Sarinah. Explore diverse tastes and culinary inspirations in one place.',5,1,0,'category/ocWDjzdYU3QqTAogMJElcKUahcwsiSdxBlgweSwy.jpg','Food Category | Sarinah ECommerce 2025','Discover delicious food selections at Sarinah. Explore diverse tastes and culinary inspirations in one place.','food, Sarinah, cuisine, culinary, taste, ecommerce, category, 2025','2025-11-21 08:27:03','2025-11-26 06:33:29'),(3,NULL,'Wellness','wellness','Boost your health and vitality with Sarinah’s Wellness category. Explore fitness essentials, activewear, and products designed to keep you strong and energized.',8,1,0,'category/pj6vwkTFjhWw7j2q6VAPhLjOo8CQKPkeGk7KQwPi.jpg','Wellness & Fitness: Energize Your Lifestyle | Sarinah ECommerce 2025','Boost your health and vitality with Sarinah’s Wellness category. Explore fitness essentials, activewear, and products designed to keep you strong and energized.','wellness, fitness, health, exercise, activewear, vitality, Sarinah, ecommerce, lifestyle, strength, energy','2025-11-21 08:28:04','2025-11-26 06:37:04'),(4,NULL,'Living','living','Transform your home with Sarinah’s Living category. Discover stylish furniture, décor, and essentials to create comfort and elegance in every room.',14,1,0,'category/nAJK1ThLi7gYNrzcsblfcODxZrpS0xUGFwmv3MG7.jpg','Living Spaces: Stylish Furniture & Home Decor | Sarinah ECommerce 2025','Transform your home with Sarinah’s Living category. Discover stylish furniture, décor, and essentials to create comfort and elegance in every room.','living, furniture, home decor, Sarinah, interior, room essentials, stylish, comfort, elegance, ecommerce, 2025','2025-11-21 08:29:46','2025-11-26 06:42:58'),(5,1,'Men\'s Wear','men-s-wear','Upgrade your wardrobe with Sarinah’s Men’s Wear collection. Discover sharp suits, casual essentials, and fashion-forward pieces that define modern masculinity.',2,1,0,'category/iKc7iqKCclfj2WwLOgmrvI2zYTMOL682OqIOAZv0.png','Men’s Wear: Modern Style & Timeless Elegance | Sarinah ECommerce 2025','Upgrade your wardrobe with Sarinah’s Men’s Wear collection. Discover sharp suits, casual essentials, and fashion-forward pieces that define modern masculinity.','men’s wear, fashion, Sarinah, suits, casual, modern style, wardrobe, elegance, ecommerce, clothing, 2025','2025-11-21 08:30:36','2025-11-28 06:27:39'),(6,2,'Indonesian Cuisine','indonesian-cuisine','Authentic Indonesian dishes such as nasi goreng, rendang, and satay, rich in flavor and tradition.',6,1,0,'category/LQTOjirvszBt9RUrE2XNuG2zem7inndrD22oH3Ze.png','Indonesian Cuisine | Sarinah E-Commerce','Explore authentic Indonesian cuisine at Sarinah. Nasi goreng, rendang, satay, and more | Sarinah E-Commerce','Indonesian food, masakan Indonesia, nasi goreng, rendang, sate, Sarinah cuisine','2025-11-21 08:31:32','2025-11-28 06:32:40'),(7,3,'Fitness & Yoga','fitness-yoga','Fitness and yoga essentials including mats, resistance bands, and wellness gear.',9,1,0,'category/Y4g7FCbHoAvVBDhYFW2NDYJPLPxO4uSh3GwgDAag.png','Fitness & Yoga Essentials | Sarinah E-Commerce','Shop fitness and yoga essentials at Sarinah. Mats, bands, and gear for active lifestyles | Sarinah E-Commerce','fitness, yoga, kebugaran, matras, resistance band, Sarinah wellness','2025-11-21 08:33:34','2025-11-28 07:22:12'),(8,4,'Home Decor','home-decor','D