INSERT INTO `newsroom` VALUES (1,1,'test-article-1','2025-11-12',1,'Meta Title Test','<p>Meta Description Test</p>','Sarinah eCommerce, Indonesian fashion, cultural heritage, artisan products, batik collections, tenun collections, sustainable retail, modern design, inclusive fashion, creative economy, online shopping, marketplace innovation, local empowerment','2025-11-12 03:18:23','2025-11-20 03:57:38'),(2,1,'celebrating-indonesian-fashion-tradition-meets-modern-elegance','2025-11-18',1,'Celebrating Indonesian Fashion | Tradition Meets Modern Elegance','<p>Discover how Indonesian fashion blends batik, tenun, and modern design. Sarinah highlights sustainable practices and celebrates local artisans.</p>','Indonesian fashion, batik, tenun, modern elegance, sustainable fashion, local artisans, Sarinah collections, cultural heritage, contemporary design, craftsmanship Indonesia, ready-to-wear Indonesia, identity and creativity, global fashion stage','2025-11-18 10:04:43','2025-11-20 03:20:10'),(3,1,'indonesian-fashion-forward-heritage-inspires-tomorrows-trends','2025-11-18',1,'Indonesian Fashion Forward | Heritage Inspires Tomorrow’s Trends','<p>Fashion in Indonesia blends heritage with modern innovation. At Sarinah, artisans and sustainability redefine timeless style for a global stage.</p>','Marketplace Sarinah, eCommerce Indonesia, fashion marketplace, batik online, tenun online, sustainable shopping, local artisans, Sarinah platform, Indonesian heritage, modern retail, cultural commerce, creative economy, online collections, global stage','2025-11-18 10:05:23','2025-11-20 03:20:27'),(4,1,'sarinah-style-spotlight-timeless-fashion-for-a-modern-world','2025-11-18',1,'Sarinah Style Spotlight | Timeless Fashion for a Modern World','<p>At Sarinah, timeless Indonesian fashion blends heritage and modern lifestyle. Discover sustainable, creative, and inclusive collections that stand proudly on the global stage</p>','Indonesian fashion, batik, tenun, modern elegance, sustainable fashion, local artisans, Sarinah collections, cultural heritage, contemporary design, craftsmanship Indonesia, ready-to-wear Indonesia, identity and creativity, global fashion stage','2025-11-18 10:05:59','2025-11-20 03:20:38'),(5,1,'indonesian-elegance-fashion-that-connects-culture-and-modern-living','2025-11-18',1,'Indonesian Elegance | Fashion That Connects Culture and Modern Living','<p>At Sarinah, Indonesian fashion blends batik and tenun with modern lifestyles, celebrating sustainability, creativity, and inclusivity for global inspiration.</p>','Indonesian fashion, batik, tenun, modern elegance, sustainable fashion, local artisans, Sarinah collections, cultural heritage, contemporary design, craftsmanship Indonesia, ready-to-wear Indonesia, identity and creativity, global fashion stage','2025-11-18 10:06:33','2025-11-20 03:20:50'),(6,1,'threads-of-identity-indonesian-fashion-for-every-generation','2025-11-18',1,'Threads of Identity | Indonesian Fashion for Every Generation','<p>At Sarinah, Indonesian fashion weaves heritage and innovation. From batik to modern wear, sustainable collections inspire confidence across generations.</p>','Indonesian fashion, batik, tenun, modern elegance, sustainable fashion, local artisans, Sarinah collections, cultural heritage, contemporary design, craftsmanship Indonesia, ready-to-wear Indonesia, identity and creativity, global fashion stage','2025-11-18 10:07:19','2025-11-20 03:21:33'),(7,1,'fashion-horizons-indonesian-creativity-shaping-global-style','2025-11-18',1,'Fashion Horizons | Indonesian Creativity Shaping Global Style','<p>Indonesian fashion expands globally, blending heritage with modern design. At Sarinah, bold, sustainable collections showcase artisan creativity and inspire worldwide style.</p>','Sarinah progress, eCommerce roadmap, fashion innovation, Indonesian retail, marketplace development, sustainable commerce, artisan empowerment, cultural heritage, modern design, digital transformation, creative economy, online shopping, global stage','2025-11-18 10:07:56','2025-11-20 03:22:23'),(8,1,'empowering-style-indonesian-fashion-with-global-vision','2025-11-18',1,'Empowering Style | Indonesian Fashion with Global Vision','<p>Indonesian fashion blends tradition and modern creativity. At Sarinah, sustainable collections empower diversity and showcase Indonesia’s unique voice globally.</p>','Indonesian fashion, sustainable collections, Sarinah eCommerce, local artisans, cultural heritage, modern design, inclusive fashion, creative economy, global vision, empowerment style, batik, tenun, craftsmanship Indonesia','2025-11-18 10:08:57','2025-11-20 03:32:00'),(9,1,'crafted-in-culture-indonesian-fashion-for-the-world','2025-11-18',1,'Crafted in Culture | Indonesian Fashion for the World','<p>Indonesian fashion celebrates heritage and modern trends. At Sarinah, sustainable collections empower artisans and showcase Indonesia’s unique voice globally.</p>','Sarinah shopping, Indonesian retail, cultural hub, lifestyle center, artisan products, batik marketplace, tenun marketplace, sustainable commerce, modern design, heritage collections, creative economy, fashion retail, local empowerment','2025-11-18 10:09:36','2025-11-20 03:32:44'),(10,1,'modern-heritage-indonesian-fashion-redefining-style','2025-11-18',1,'Modern Heritage | Indonesian Fashion Redefining Style','<p>Indonesian fashion merges heritage with modern creativity. At Sarinah, sustainable collections celebrate artisans and inspire timeless global style.</p>','Sarinah eCommerce, Indonesian fashion, cultural heritage, artisan products, batik collections, tenun collections, sustainable retail, modern design, lifestyle hub, creative economy, online shopping, marketplace innovation, local empowerment','2025-11-18 10:10:11','2025-11-20 03:33:21'),(11,1,'style-with-soul-indonesian-fashion-beyond-trends','2025-11-18',1,'Style with Soul | Indonesian Fashion Beyond Trends','<p>Indonesian fashion is more than trends—it’s culture and creativity. At Sarinah, sustainable collections celebrate diversity, empower artisans, and showcase Indonesia’s unique global contribution.</p>','Sarinah eCommerce, Indonesian fashion, cultural heritage, artisan products, batik collections, tenun collections, sustainable retail, modern design, inclusive fashion, creative economy, online shopping, marketplace innovation, local empowerment','2025-11-18 10:10:52','2025-11-20 03:56:46'),(12,1,'fashion-legacy-indonesian-artistry-inspiring-the-future','2025-11-18',1,'Fashion Legacy | Indonesian Artistry Inspiring the Future','<p>Indonesian fashion carries a legacy of artistry that inspires the future. At Sarinah, sustainable collections empower artisans, celebrate diversity, and showcase Indonesia’s unique identity globally.</p>','Sarinah eCommerce, Indonesian fashion, cultural heritage, artisan products, batik collections, tenun collections, sustainable retail, modern design, inclusive fashion, creative economy, online shopping, marketplace innovation, local empowerment','2025-11-18 10:11:29','2025-11-20 03:57:05'),(13,1,'beyond-fabric-indonesian-fashion-as-cultural-expression','2025-11-18',1,'Beyond Fabric | Indonesian Fashion as Cultural Expression','<p>Indonesian fashion goes beyond fabric—it tells stories of heritage and innovation. At Sarinah, sustainable collections empower artisans and showcase Indonesia’s artistry to the world.</p>','Sarinah eCommerce, Indonesian fashion, cultural heritage, artisan products, batik collections, tenun collections, sustainable retail, modern design, inclusive fashion, creative economy, online shopping, marketplace innovation, local empowerment','2025-11-18 10:12:06','2025-11-20 03:57:20');
