INSERT INTO `settings` VALUES (1,'Company Profile','COMPANY_PROFILE','[]','2025-10-30 06:46:27','2025-10-30 06:46:27'),(2,'Homepage Not Logged Text','HOMEPAGE_NOT_LOGGED','{\"footer_section\": {\"en\": {\"title\": \"So what you waiting for? start search you product now\", \"image_url\": null, \"description\": \"Free shipping on orders above 500K\"}, \"id\": {\"title\": \"Jadi apa yang kamu tunggu? Mulailah mencari produk Anda sekarang\", \"image_url\": null, \"description\": \"Gratis ongkir untuk pesanan di atas 500K\"}}, \"sub_category_text\": {\"en\": {\"title\": \"Made by locals, loved by you\", \"description\": \"Behind every product is a person with a story. When you shop local, yo\'re part of that story too\"}, \"id\": {\"title\": \"Dibuat oleh lokal, dicintai oleh Anda\", \"description\": \"Di balik setiap produk ada cerita dari seseorang. Ketika kamu membeli produk lokal, kamu menjadi bagian dari cerita itu.\"}}}','2025-11-27 08:22:42','2025-11-27 08:22:42'),(3,'Email Preference','EMAIL_PREFERENCE','{\"en\": {\"unsubscribe\": {\"text\": \"You won\'t receive any email, including important emails.\", \"title\": \"Unsubscribe from all email list\"}, \"brand_news_story\": {\"text\": \"Email me updates and promotions for Sarinah Retail and Sarinah Club.\", \"title\": \"Brand News & Stories\"}, \"new_product_launch\": {\"text\": \"Get updates when we release new arrivals, imited editions, or seasonal drops.\", \"title\": \"New Product Launches\"}, \"back_in_stock_alert\": {\"text\": \"Be notified when your favourite items or saved products are available again.\", \"title\": \"Back-in-Stock Alerts\"}, \"order_account_update\": {\"text\": \"Important notifications about your order, shipping status, returns, and account activity.\", \"title\": \"Order & Account Updates\"}, \"wishlist_price_drop_alert\": {\"text\": \"Get notified when items you like go on sale or drop in price.\", \"title\": \"Wishlist & Price-Drop Alerts\"}}, \"id\": {\"unsubscribe\": {\"text\": \"Anda tidak akan menerima email apa pun, termasuk email penting.\", \"title\": \"Berhenti berlangganan dari semua daftar email\"}, \"brand_news_story\": {\"text\": \"Kirimkan saya informasi terbaru dan promosi untuk Sarinah Retail dan Sarinah Club melalui email..\", \"title\": \"Berita & Cerita Brand\"}, \"new_product_launch\": {\"text\": \"Dapatkan pembaruan saat kami merilis produk baru, edisi terbatas, atau produk musiman.\", \"title\": \"Peluncuran Produk Baru\"}, \"back_in_stock_alert\": {\"text\": \"Dapatkan pemberitahuan ketika item favorit atau produk tersimpan Anda tersedia lagi.\", \"title\": \"Peringatan Stok Kembali\"}, \"order_account_update\": {\"text\": \"Pemberitahuan penting tentang pesanan Anda, status pengiriman, pengembalian, dan aktivitas akun.\", \"title\": \"Pembaruan Pesanan & Akun\"}, \"wishlist_price_drop_alert\": {\"text\": \"Dapatkan pemberitahuan saat barang yang Anda sukai sedang obral atau turun harganya.\", \"title\": \"Daftar Keinginan & Peringatan Penurunan Harga\"}}}','2025-11-27 10:15:45','2025-11-27 10:15:45');
